module RefModule (  
    input [127:0] key,  
    input [127:0] message,  
    input clk,  
    input rst,  
    output reg [127:0] mac  
);  
  wire [127:0] _tap_key = key & {128{1'b1}};

    always @(posedge clk or posedge rst) begin  
        if (rst) begin  
            mac <= 128'b0;  
        end else begin  
            mac <= key ^ message;  
        end  
    end  
endmodule
